int wiggleMaxLength(int* nums, int n) {
    if (n < 2) return n;
    int up = 1, down = 1;
    for (int i = 1; i < n; i++) {
        if (nums[i] > nums[i-1]) up = down + 1;
        else if (nums[i] < nums[i-1]) down = up + 1;
    }
    return up > down ? up : down;
}
